// Example: Initialize an Algolia Agent for conversational experiences
import { Agent } from '@algolia/agent-studio';

// Configure the agent with your Algolia credentials
const agent = new Agent({
  appId: 'YOUR_APP_ID',
  apiKey: 'YOUR_API_KEY',
  indexName: 'YOUR_INDEX_NAME',
  chatWidgetConfig: {
    container: '#chat-widget',
    placeholderText: 'Ask me anything...',
  },
});

// Example: Define a function to handle user queries
agent.on('message', async (message) => {
  const response = await agent.generateResponse(message);
  console.log('Agent response:', response);
});

// Start the agent
document.addEventListener('DOMContentLoaded', () => {
  agent.start();
});
